interface ClientApplications {
  allSupervisedLoanApps: GetsupervisedAppsRequest[];
  chosenApplicationKey: string;
}
@Component({
  selector: "app-review-for-others",
  templateUrl: "./review-for-others.page.html",
  styleUrls: ["./review-for-others.page.scss"],
})
export class ReviewForOthersPage implements OnInit {
  showLoader: boolean = false;
  revisionFormStatus: FormStatus = { valid: false, visible: false };
  ClientApplications: ClientApplications = {
    allSupervisedLoanApps: [],
    chosenApplicationKey: null,
  };
  sortingObject: { sortingIconClass: string; sortingIconParam: string } = {
    sortingIconClass: null,
    sortingIconParam: null,
  };
  pagingObject: { page: number } = {
    page: 1,
  };
  constructor(
    private loanApplicationService: LoanApplicationsService,
    public pagingService: pagingService,
    private sortingService: sortingService
  ) {}
  async ngOnInit() {
    this.ClientApplications.allSupervisedLoanApps =
      await this.loanApplicationService.getAllSupervisedLoanApps();
  }
  async reviewApplication(applicationKey: string) {
    this.ClientApplications.chosenApplicationKey = applicationKey;
    this.revisionFormStatus.visible = true;
  }
  changePaginationPage = (newPage: number): void => {
    this.pagingObject.page = newPage;
  };
  sortingTable(data: any, param: string) {
    this.sortingService.sortByParameter(data, param);
    this.sortingObject.sortingIconClass =
      this.sortingService.sortOrder === "asc"
        ? "arrow-down-outline"
        : "arrow-up-outline";
    this.sortingObject.sortingIconParam = param;
  }
}
